#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>

typedef struct FileHandle {
    int fd;
    struct FileHandle *next;
} FileHandle;

FileHandle *head = NULL;

void add(int fd) {
    FileHandle *new_handle = (FileHandle *)malloc(sizeof(FileHandle));
    new_handle->fd = fd;
    new_handle->next = head;
    head = new_handle;
}

void remove(int fd) {
    FileHandle **current = &head;
    
    while (*current != NULL) {
        if ((*current)->fd == fd) {
            FileHandle *temp = *current;
            *current = (*current)->next;
            free(temp);
            return;
        }
        current = &((*current)->next);
    }
}

void cleanup() {
    FileHandle *current = head;
    
    while (current != NULL) {
        close(current->fd);
        FileHandle *temp = current;
        current = current->next;
        free(temp);
    }
    
    head = NULL;
}